## Migration Analysis

Your code has **three** patterns that break on .NET 8:

| API | Problem on .NET 8 | Pattern |
|-----|-------------------|---------|
| `Thread.Interrupt()` | Obsolete (`SYSLIB0046` in .NET 9), unreliable | Blocking call interruption |
| `Thread.Abort()` | Throws `PlatformNotSupportedException` | Timeout enforcement / forced kill |
| `while (true)` + `WaitOne()` | No cooperative exit | Cancellable work loop |

---

## Migrated Code (.NET 8)

```csharp
using System.Threading.Channels;

public class EventProcessor : IDisposable
{
    private readonly Channel<string> _channel = Channel.CreateUnbounded<string>();
    private readonly CancellationTokenSource _cts = new();
    private Task? _processTask;

    public void Start()
    {
        _processTask = Task.Run(() => RunLoopAsync(_cts.Token));
    }

    private async Task RunLoopAsync(CancellationToken token)
    {
        try
        {
            await foreach (var item in _channel.Reader.ReadAllAsync(token))
            {
                Handle(item);
            }
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            // Normal shutdown — nothing to do
        }
    }

    public void Enqueue(string item)
    {
        _channel.Writer.TryWrite(item);
    }

    public async Task StopAsync(TimeSpan? timeout = null)
    {
        _channel.Writer.Complete(); // signals no more items
        _cts.CancelAfter(timeout ?? TimeSpan.FromSeconds(5)); // hard deadline

        if (_processTask is not null)
            await _processTask;
    }

    public void Dispose()
    {
        _cts.Dispose();
    }

    private void Handle(string item) { /* your logic */ }
}
```

